INSERT INTO science_schedule (id, title, overview, current_exam_subject, current_exam_range_start, current_exam_note, updated_at) VALUES ('science-schedule-main', 'SNC1W Semester 2 (2025-2026)', 'Based on the course calendar, Semester 2 runs from February 2, 2026 to the June 2026 exam period and moves through Inquiry, Chemistry, Space, Electricity, and Biology/Ecology.', 'Chemistry', '2026-03-23', 'Content posted on or after March 23, 2026 is part of the next Chemistry test range.', '2026-04-03T22:28:11.611Z');
INSERT INTO science_schedule_units (id, schedule_id, unit_order, name, window_label, focus, notes) VALUES ('science-unit-58e60799294e00a3', 'science-schedule-main', 0, 'Inquiry', 'February 2 to February 24, 2026', 'Skills', 'Scientific questioning, controlled experiments, metric system, graphing, lab reports, and measurement investigations.');
INSERT INTO science_schedule_units (id, schedule_id, unit_order, name, window_label, focus, notes) VALUES ('science-unit-2942510f4fe7a516', 'science-schedule-main', 1, 'Chemistry', 'February 25 to April 13, 2026', 'Matter', 'Classification of matter, particle theory, physical and chemical change, periodic table, metals and non-metals, gas tests, atomic structure, bonding, and chemical formulas.');
INSERT INTO science_schedule_units (id, schedule_id, unit_order, name, window_label, focus, notes) VALUES ('science-unit-a42779e354e68982', 'science-schedule-main', 2, 'Space', 'April 14 to May 4, 2026', 'Astronomy', 'Earth-Moon-Sun interactions, eclipses, northern lights, spectroscopy, star life cycles, big bang theory, and space exploration.');
INSERT INTO science_schedule_units (id, schedule_id, unit_order, name, window_label, focus, notes) VALUES ('science-unit-6d42ad266dc27a45', 'science-schedule-main', 3, 'Electricity', 'May 4 to May 28, 2026', 'Circuits', 'Static electricity, charging, circuit diagrams, series and parallel circuits, current, voltage, resistance, and Ohm''s law.');
INSERT INTO science_schedule_units (id, schedule_id, unit_order, name, window_label, focus, notes) VALUES ('science-unit-390dbd2feb3d4bf9', 'science-schedule-main', 4, 'Biology / Ecology', 'May 29 to June 12, 2026', 'Ecosystems', 'Energy flow, cycling of matter, biodiversity, climate and food security, and human effects on ecosystems.');
INSERT INTO science_schedule_key_dates (id, schedule_id, date_order, date_label, label, note) VALUES ('science-key-date-a65b1989375cadbe', 'science-schedule-main', 0, 'February 24, 2026', 'Inquiry unit test and rotocopter lab report due', 'Inquiry assessment checkpoint before Chemistry begins.');
INSERT INTO science_schedule_key_dates (id, schedule_id, date_order, date_label, label, note) VALUES ('science-key-date-132c122784862ca0', 'science-schedule-main', 1, 'March 13, 2026', 'Chemistry quiz', 'Includes learning up to and including physical and chemical change.');
INSERT INTO science_schedule_key_dates (id, schedule_id, date_order, date_label, label, note) VALUES ('science-key-date-990918bee407c04b', 'science-schedule-main', 2, 'March 26, 2026', 'Metals and non-metals lab analysis due in class', 'Comes right before gas test prep and atomic theory work.');
INSERT INTO science_schedule_key_dates (id, schedule_id, date_order, date_label, label, note) VALUES ('science-key-date-c7793f3bbd6e6261', 'science-schedule-main', 3, 'April 7, 2026', 'Atomic structure practice quiz and Chemistry article evaluation', 'Students will write the practice quiz and complete the Chemistry article evaluation on the same day.');
INSERT INTO science_schedule_key_dates (id, schedule_id, date_order, date_label, label, note) VALUES ('science-key-date-28cf22a371534b68', 'science-schedule-main', 4, 'April 13, 2026', 'Chemistry unit test', 'Older course calendar note listed April 13, but the latest family update says the Chemistry unit test will be written on Wednesday April 15, 2026.');
INSERT INTO science_schedule_key_dates (id, schedule_id, date_order, date_label, label, note) VALUES ('science-key-date-e9424c716b111f3a', 'science-schedule-main', 5, 'April 15, 2026', 'Chemistry unit test', 'Teacher update: the Chemistry unit test is on Wednesday April 15, 2026. A review package should arrive one week before the test.');
INSERT INTO science_schedule_key_dates (id, schedule_id, date_order, date_label, label, note) VALUES ('science-key-date-9ee68cf4041fb0ba', 'science-schedule-main', 6, 'May 4, 2026', 'Space unit test', 'Wraps the Space unit and begins the Electricity unit the same day.');
INSERT INTO science_schedule_key_dates (id, schedule_id, date_order, date_label, label, note) VALUES ('science-key-date-5bad9eb521dab5a4', 'science-schedule-main', 7, 'May 14, 2026', 'Electricity quiz: static electricity', 'Mid-unit checkpoint during current electricity and circuits.');
INSERT INTO science_schedule_key_dates (id, schedule_id, date_order, date_label, label, note) VALUES ('science-key-date-35bbe05a7d4b4d8b', 'science-schedule-main', 8, 'May 28, 2026', 'Electricity unit test', 'Final electricity assessment before Biology / Ecology starts.');
INSERT INTO science_schedule_key_dates (id, schedule_id, date_order, date_label, label, note) VALUES ('science-key-date-76b4f4989bb44850', 'science-schedule-main', 9, 'June 12, 2026', 'Ecology unit test', 'Final unit test before review days and exam week.');
INSERT INTO science_schedule_key_dates (id, schedule_id, date_order, date_label, label, note) VALUES ('science-key-date-6c6b474b2b423ee5', 'science-schedule-main', 10, 'June 18 to June 24, 2026', 'Exam period', 'Block exam days begin June 18, 2026 and continue through June 24, 2026.');
INSERT INTO upcoming_support_items (id, subject_slug, when_label, topic, support_type, summary, source_kind, source_upload_id, created_at, updated_at) VALUES ('upcoming-support-3a4987e5bc7bfbb1', 'science', 'Tuesday, April 7, 2026', 'Practice quiz', 'Assessment', 'This atomic structure practice quiz uses the periodic table. Kevin needs to find protons, electrons, and neutrons, know element symbols, and explain the difference between atomic mass and mass number.', 'manual', NULL, '2026-04-03T22:28:11.612Z', '2026-04-03T22:28:11.612Z');
