INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-572245351392983b', 'upcoming-support-0e730d71d3fe103b', 'beforeClass', 'Before class', 0, 'text', 'Atomic mass uses the unit u, which means atomic mass unit.', NULL, NULL);
INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-5c91708e635101a4', 'upcoming-support-0e730d71d3fe103b', 'beforeClass', 'Before class', 1, 'text', 'u is a very small unit used for atoms; it is not the same as grams.', NULL, NULL);
