INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-0e83c9e149c4f280', 'upcoming-support-0e730d71d3fe103b', 'flexibleThinkingExamples', 'Flexible thinking', 0, 'text', 'Hydrogen-1 is the most common isotope: 1 proton, 0 neutrons.', NULL, NULL);
