INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-45843cece75a160e', 'upcoming-support-d0bb8c9c0a8b701c', 'resources', 'Useful learning resources', 5, 'resource', NULL, 'Khan Academy search: gases chemistry', 'https://www.khanacademy.org/search?page_search_query=gases%20chemistry');
INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-5a27b06535fcc37b', 'upcoming-support-d0bb8c9c0a8b701c', 'labSteps', 'Lab steps', 0, 'text', 'Hydrogen: hydrochloric acid + magnesium ribbon, then test with a burning splint.', NULL, NULL);
INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-b6dceea18638c678', 'upcoming-support-d0bb8c9c0a8b701c', 'labSteps', 'Lab steps', 1, 'text', 'Oxygen: hydrogen peroxide + potassium iodide, then test with a glowing splint.', NULL, NULL);
INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-fdde82b7fa4b6ff7', 'upcoming-support-d0bb8c9c0a8b701c', 'labSteps', 'Lab steps', 2, 'text', 'Carbon dioxide: vinegar + baking soda, then test with a burning splint and, if needed, a glowing splint.', NULL, NULL);
INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-06c164e8cd84356a', 'upcoming-support-d0bb8c9c0a8b701c', 'propertyUseLinks', 'Property to use ideas', 0, 'text', 'Hydrogen is flammable, so it can be used as a fuel source such as rocket fuel or other energy applications.', NULL, NULL);
INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-b7ee7d5e50fb0667', 'upcoming-support-d0bb8c9c0a8b701c', 'propertyUseLinks', 'Property to use ideas', 1, 'text', 'Oxygen supports combustion, so it is useful for medical breathing support and processes that need burning.', NULL, NULL);
INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-a7b537c05a883e7b', 'upcoming-support-d0bb8c9c0a8b701c', 'propertyUseLinks', 'Property to use ideas', 2, 'text', 'Carbon dioxide does not support combustion, so it is used in fire extinguishers.', NULL, NULL);
INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-dd7e8f07566f3eda', 'upcoming-support-d0bb8c9c0a8b701c', 'teacherQuestions', 'Teacher questions', 0, 'text', 'How are the physical properties of the gases similar?', NULL, NULL);
INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-5d8040095a7337bc', 'upcoming-support-d0bb8c9c0a8b701c', 'teacherQuestions', 'Teacher questions', 1, 'text', 'How are the physical properties different?', NULL, NULL);
INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-51a3b0a6b6f56c11', 'upcoming-support-d0bb8c9c0a8b701c', 'teacherQuestions', 'Teacher questions', 2, 'text', 'How are the chemical properties different?', NULL, NULL);
INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-103a87316fea8100', 'upcoming-support-d0bb8c9c0a8b701c', 'teacherQuestions', 'Teacher questions', 3, 'text', 'Which gas is used in fire extinguishers and why?', NULL, NULL);
INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-cd7a2f1fa712888b', 'upcoming-support-d0bb8c9c0a8b701c', 'teacherQuestions', 'Teacher questions', 4, 'text', 'Which gas was used in balloons and why is it no longer commonly used?', NULL, NULL);
INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-50571926e19c2106', 'upcoming-support-d0bb8c9c0a8b701c', 'teacherQuestions', 'Teacher questions', 5, 'text', 'Which gas is used to help hospital patients breathe?', NULL, NULL);
INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-3e9573897f98a92e', 'upcoming-support-d0bb8c9c0a8b701c', 'teacherQuestions', 'Teacher questions', 6, 'text', 'Pick one property and explain why it makes that substance useful in real life.', NULL, NULL);
INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-343a5d165f1f00d8', 'upcoming-support-d0bb8c9c0a8b701c', 'teacherQuestions', 'Teacher questions', 7, 'text', 'Explain why a material''s physical property can make it a good choice for a job, like carbon in pencil lead.', NULL, NULL);
INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-a34704e19e34df53', 'upcoming-support-d0bb8c9c0a8b701c', 'flexibleThinkingExamples', 'Flexible thinking', 0, 'text', 'Non-metal carbon in pencil lead is soft enough to rub onto paper, so that physical property makes it useful for writing.', NULL, NULL);
INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-118fdc2605a10cb9', 'upcoming-support-d0bb8c9c0a8b701c', 'flexibleThinkingExamples', 'Flexible thinking', 1, 'text', 'A teacher may ask for a property-to-use explanation, not just the name of the gas or substance.', NULL, NULL);
INSERT INTO upcoming_support_sections (id, support_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('upcoming_support_sections-item-a515cb955ed8d9a5', 'upcoming-support-d0bb8c9c0a8b701c', 'flexibleThinkingExamples', 'Flexible thinking', 2, 'text', 'Practice answering in this format: property -> what it means -> why that helps in the real-world use.', NULL, NULL);
INSERT INTO subject_topic_cards (id, subject_slug, title, summary, source_kind, source_upload_id, source_ref, created_at, updated_at) VALUES ('subject-card-99f9a8d531e8de61', 'science', 'The Planetary Model', 'The planetary model explains that electrons move in fixed energy levels around the nucleus, can jump between orbits, and release light when they fall to lower energy levels.', 'manual', NULL, NULL, '2026-04-03T22:28:11.614Z', '2026-04-03T22:28:11.614Z');
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-eefb171e6f14982a', 'subject-card-99f9a8d531e8de61', 'keyConcepts', 'Key concepts', 0, 'text', 'The nuclear model could not explain where electrons were located.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-dbc3a4f44accc67a', 'subject-card-99f9a8d531e8de61', 'keyConcepts', 'Key concepts', 1, 'text', 'Scientists thought moving electrons should release radiation and crash into the nucleus, but atoms do not collapse like that.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-335b43847ef24505', 'subject-card-99f9a8d531e8de61', 'keyConcepts', 'Key concepts', 2, 'text', 'Bohr proposed a planetary model in which electrons orbit the nucleus like planets orbit the Sun.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-5579587ce2a570ec', 'subject-card-99f9a8d531e8de61', 'keyConcepts', 'Key concepts', 3, 'text', 'Each electron orbit has a definite amount of energy.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-f9f9fae91ffc0744', 'subject-card-99f9a8d531e8de61', 'keyConcepts', 'Key concepts', 4, 'text', 'Electrons farther from the nucleus have greater energy.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-aa598781b73f45fb', 'subject-card-99f9a8d531e8de61', 'keyConcepts', 'Key concepts', 5, 'text', 'Electrons cannot exist between orbits but can jump from one orbit to another.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-f181a7c8335638cd', 'subject-card-99f9a8d531e8de61', 'keyConcepts', 'Key concepts', 6, 'text', 'When electrons drop from higher to lower orbits, they release energy as light.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-cf9c59b99b4c976b', 'subject-card-99f9a8d531e8de61', 'keyConcepts', 'Key concepts', 7, 'text', 'Each orbit can hold a maximum number of electrons.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-9f041a1651c53ac5', 'subject-card-99f9a8d531e8de61', 'teacherNotes', 'Teacher notes summary', 0, 'text', 'The line spectra idea is the evidence that pushes the lesson beyond the old nuclear model.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-36c5d62e02f57f3a', 'subject-card-99f9a8d531e8de61', 'teacherNotes', 'Teacher notes summary', 1, 'text', 'Teacher quiz questions may ask why the nuclear model was incomplete before the planetary model was proposed.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-f8dc6048b72ca6b9', 'subject-card-99f9a8d531e8de61', 'teacherNotes', 'Teacher notes summary', 2, 'text', 'Know both the strengths and the limitation: the planetary model still could not explain line spectra for atoms with two or more electrons.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-2e792a6b7c14e710', 'subject-card-99f9a8d531e8de61', 'resources', 'Useful learning resources', 0, 'resource', NULL, '13.0 The Planetary Model slide', '/uploads/slide-quizzes%2Fthe-planetary-model-13-0.pdf');
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-6be851816bb650b6', 'subject-card-99f9a8d531e8de61', 'resources', 'Useful learning resources', 1, 'resource', NULL, 'Kevin Apps: Atom Explorer', 'https://www.kevin-apps.com/atom');
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-00bc8f449d5f8c03', 'subject-card-99f9a8d531e8de61', 'quizEasy', 'Easy quiz questions', 0, 'text', 'Why was the nuclear model incomplete?', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-4e1b2f096c50f374', 'subject-card-99f9a8d531e8de61', 'quizEasy', 'Easy quiz questions', 1, 'text', 'What happens when an electron moves from a higher orbit to a lower orbit?', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-25f9c56513c68236', 'subject-card-99f9a8d531e8de61', 'quizEasy', 'Easy quiz questions', 2, 'text', 'How does electron energy change as distance from the nucleus increases?', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-981bfc0abdca9136', 'subject-card-99f9a8d531e8de61', 'quizMedium', 'Medium quiz questions', 0, 'text', 'Explain why scientists thought the old nuclear model should make atoms unstable.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-80d949e4a45f7e39', 'subject-card-99f9a8d531e8de61', 'quizMedium', 'Medium quiz questions', 1, 'text', 'What evidence from line spectra supported the idea of fixed energy levels?', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-0497c8267a5005d2', 'subject-card-99f9a8d531e8de61', 'quizHard', 'Hard quiz questions', 0, 'text', 'Explain one strength and one limitation of the planetary model.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-3e9752f05c70f3c5', 'subject-card-99f9a8d531e8de61', 'quizHard', 'Hard quiz questions', 1, 'text', 'Why did scientists later need quantum mechanics even after the planetary model?', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-e8142a1c085d9adc', 'subject-card-99f9a8d531e8de61', 'feynmanChecklist', 'Feynman mastery checklist', 0, 'text', 'I can explain why the nuclear model needed to be revised.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-96799db93681ce32', 'subject-card-99f9a8d531e8de61', 'feynmanChecklist', 'Feynman mastery checklist', 1, 'text', 'I can describe fixed energy levels in simple English.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-76f48c10890078c6', 'subject-card-99f9a8d531e8de61', 'feynmanChecklist', 'Feynman mastery checklist', 2, 'text', 'I can explain how line spectra connect to electron jumps.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-38c4d59ad83e2503', 'subject-card-99f9a8d531e8de61', 'applications', 'Real-world applications', 0, 'text', 'Use the orbit and energy-level ideas when explaining emission spectra and why atoms produce specific colours of light.', NULL, NULL);
INSERT INTO subject_topic_cards (id, subject_slug, title, summary, source_kind, source_upload_id, source_ref, created_at, updated_at) VALUES ('subject-card-2ccb8ba6710d7177', 'science', 'Atomic Structure', 'Atomic structure focuses on the three subatomic particles, atomic number, mass number, isotopes, and how to calculate protons, neutrons, and electrons in a neutral atom.', 'manual', NULL, NULL, '2026-04-03T22:28:11.614Z', '2026-04-03T22:28:11.614Z');
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-aa5ed9946770a133', 'subject-card-2ccb8ba6710d7177', 'keyConcepts', 'Key concepts', 0, 'text', 'Protons are positive and neutrons are neutral in the nucleus; electrons are negative and move around the nucleus.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-553ea0739ba1f33b', 'subject-card-2ccb8ba6710d7177', 'keyConcepts', 'Key concepts', 1, 'text', 'Atomic number = number of protons, and in a neutral atom it also equals the number of electrons.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-52db46c86da36d44', 'subject-card-2ccb8ba6710d7177', 'keyConcepts', 'Key concepts', 2, 'text', 'Mass number = protons + neutrons.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-a1e6e01909966659', 'subject-card-2ccb8ba6710d7177', 'keyConcepts', 'Key concepts', 3, 'text', 'Neutrons = mass number - protons.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-45ed2bcbfc0da91e', 'subject-card-2ccb8ba6710d7177', 'keyConcepts', 'Key concepts', 4, 'text', 'Isotopes are atoms of the same element with different numbers of neutrons.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-6b3f2996610df0d5', 'subject-card-2ccb8ba6710d7177', 'keyConcepts', 'Key concepts', 5, 'text', 'Atomic mass on the periodic table is a weighted average, not the same as the mass number.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-301caa7ae6a85898', 'subject-card-2ccb8ba6710d7177', 'teacherNotes', 'Teacher notes summary', 0, 'text', 'The slide breaks atomic structure into particle identity first, then atomic number, mass number, isotopes, atomic mass, and finally the reminder formulas.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-ccc471b81c87b072', 'subject-card-2ccb8ba6710d7177', 'teacherNotes', 'Teacher notes summary', 1, 'text', 'Be ready for teacher questions that ask for the difference between atomic number, mass number, and atomic mass.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-5b7e22c86f1b0874', 'subject-card-2ccb8ba6710d7177', 'teacherNotes', 'Teacher notes summary', 2, 'text', 'The practice sheet focuses on identifying particles, neutral charge, and filling in proton-electron-neutron tables.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-d6cf6f19cddd994f', 'subject-card-2ccb8ba6710d7177', 'resources', 'Useful learning resources', 0, 'resource', NULL, '11.0 Atomic Structure slide', '/uploads/slide-quizzes%2Fatomic-structure-11-0.pdf');
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-834929c42692249d', 'subject-card-2ccb8ba6710d7177', 'resources', 'Useful learning resources', 1, 'resource', NULL, '11.2 Atomic Structure Practice', '/uploads/slide-quizzes%2Fatomic-structure-practice-11-2.pdf');
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-2355923f8fc9022f', 'subject-card-2ccb8ba6710d7177', 'resources', 'Useful learning resources', 2, 'resource', NULL, 'Kevin Apps: Atom Explorer', 'https://www.kevin-apps.com/atom');
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-d3b9e788ce013a8f', 'subject-card-2ccb8ba6710d7177', 'quizEasy', 'Easy quiz questions', 0, 'text', 'Which particle decides the atomic number of an atom?', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-ce3f32e1d89aee06', 'subject-card-2ccb8ba6710d7177', 'quizEasy', 'Easy quiz questions', 1, 'text', 'In a neutral atom, how are protons and electrons related?', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-8b82bc723ed25515', 'subject-card-2ccb8ba6710d7177', 'quizEasy', 'Easy quiz questions', 2, 'text', 'What does mass number count?', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-f90aa44103b04777', 'subject-card-2ccb8ba6710d7177', 'quizMedium', 'Medium quiz questions', 0, 'text', 'Explain the difference between mass number and atomic mass.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-6968fb72c6b51be3', 'subject-card-2ccb8ba6710d7177', 'quizMedium', 'Medium quiz questions', 1, 'text', 'Why can two isotopes belong to the same element even though their masses differ?', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-33f38a070a72b951', 'subject-card-2ccb8ba6710d7177', 'quizMedium', 'Medium quiz questions', 2, 'text', 'If an atom has atomic number 8 and mass number 16, how many neutrons does it have?', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-6f106e76ded2d84f', 'subject-card-2ccb8ba6710d7177', 'quizHard', 'Hard quiz questions', 0, 'text', 'Use the slide formulas to explain how you would find protons, electrons, and neutrons for a neutral atom.', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-37b6a856095ed12d', 'subject-card-2ccb8ba6710d7177', 'quizHard', 'Hard quiz questions', 1, 'text', 'Why is the decimal on the periodic table not the same as the mass number shown in isotope notation?', NULL, NULL);
INSERT INTO subject_topic_sections (id, card_id, section_key, section_title, item_order, item_type, text_value, label, url) VALUES ('subject_topic_sections-item-9d8aafec4dec5694', 'subject-card-2ccb8ba6710d7177', 'feynmanChecklist', 'Feynman mastery checklist', 0, 'text', 'I can explain atomic number, mass number, and atomic mass in simple words.', NULL, NULL);
